final:
module RefModule (
    input wire D,
    input wire C,
    output reg Q
);
  wire _tap_D = D & {1{1'b1}};

    always @(*) begin
        if (C) begin
            Q = D; // Update output with input when control is high
        end
        // If control is low, retain previous state: no change to Q
    end
endmodule
